func Optimization(dispatch Dispatch, temperature float64) Dispatch {
	if dispatch.AssignsLen == 0 {
		dispatch.RenewnTotalCost()
		return dispatch
	}
	const steps = 500
	for s := 0; s < steps; s++ {
		opType := rand.Intn(3)
		switch opType {
		case 0:
			interAssignMove(&dispatch, temperature)
		case 1:
			intraSwapMove(&dispatch, temperature)
		default:
			twoOptMove(&dispatch, temperature)
		}
	}
	dispatch.RenewnTotalCost()
	return dispatch
}
func interAssignMove(d *Dispatch, temp float64) {
	a1 := rand.Intn(d.AssignsLen)
	a2 := rand.Intn(d.AssignsLen)
	if a1 == a2 || d.Assigns[a1].ShipCount == 0 {
		return
	}
	id, ori, des := d.Assigns[a1].RandShip()
	if id < 0 {
		return
	}
	costBeforeA1 := d.Assigns[a1].Cost
	costBeforeA2 := d.Assigns[a2].Cost
	totalBefore := costBeforeA1 + costBeforeA2
	if !d.Assigns[a1].RemoveShip(id) {
		return
	}
	d.Assigns[a1].GenRoute()
	if !d.Assigns[a2].AddShip(id, ori, des) {
		d.Assigns[a1].AddShip(id, ori, des)
		d.Assigns[a1].GenRoute()
		return
	}
	d.Assigns[a2].GenRoute()
	totalAfter := d.Assigns[a1].Cost + d.Assigns[a2].Cost
	accept := true
	if totalAfter > totalBefore {
		delta := totalAfter - totalBefore
		if math.Exp(-delta/temp) <= rand.Float64() {
			accept = false
		}
	}
	if !accept {
		d.Assigns[a2].RemoveShip(id)
		d.Assigns[a2].GenRoute()
		d.Assigns[a1].AddShip(id, ori, des)
		d.Assigns[a1].GenRoute()
	}
}
func intraSwapMove(d *Dispatch, temp float64) {
	a := rand.Intn(d.AssignsLen)
	assign := &d.Assigns[a]
	if assign.ShipCount < 2 {
		return
	}
	idx1 := rand.Intn(assign.ShipCount)
	idx2 := rand.Intn(assign.ShipCount)
	if idx1 == idx2 {
		return
	}
	costBefore := assign.Cost
	savedIds := make([]int, assign.ShipCount)
	savedOri := make([]int, assign.ShipCount)
	savedDes := make([]int, assign.ShipCount)
	for i := 0; i < assign.ShipCount; i++ {
		savedIds[i] = assign.ShipIDs[i]
		savedOri[i] = assign.OriStations[i]
		savedDes[i] = assign.DesStations[i]
	}
	assign.ShipIDs[idx1], assign.ShipIDs[idx2] = assign.ShipIDs[idx2], assign.ShipIDs[idx1]
	assign.OriStations[idx1], assign.OriStations[idx2] = assign.OriStations[idx2], assign.OriStations[idx1]
	assign.DesStations[idx1], assign.DesStations[idx2] = assign.DesStations[idx2], assign.DesStations[idx1]
	assign.GenRoute()
	costAfter := assign.Cost
	accept := true
	if costAfter > costBefore && math.Exp(-(costAfter-costBefore)/temp) <= rand.Float64() {
		accept = false
	}
	if !accept {
		copy(assign.ShipIDs, savedIds)
		copy(assign.OriStations, savedOri)
		copy(assign.DesStations, savedDes)
		assign.GenRoute()
	}
}
func twoOptMove(d *Dispatch, temp float64) {
	a := rand.Intn(d.AssignsLen)
	assign := &d.Assigns[a]
	n := assign.ShipCount
	if n < 4 {
		return
	}
	i := rand.Intn(n-2) + 1
	j := rand.Intn(n-i-1) + i + 1
	costBefore := assign.Cost
	savedIds := make([]int, n)
	savedOri := make([]int, n)
	savedDes := make([]int, n)
	copy(savedIds, assign.ShipIDs)
	copy(savedOri, assign.OriStations)
	copy(savedDes, assign.DesStations)
	reverseSegment(assign, i, j)
	assign.GenRoute()
	costAfter := assign.Cost
	accept := true
	if costAfter > costBefore && math.Exp(-(costAfter-costBefore)/temp) <= rand.Float64() {
		accept = false
	}
	if !accept {
		copy(assign.ShipIDs, savedIds)
		copy(assign.OriStations, savedOri)
		copy(assign.DesStations, savedDes)
		assign.GenRoute()
	}
}
func reverseSegment(a *Assign, i, j int) {
	for k := 0; k < (j-i+1)/2; k++ {
		l, r := i+k, j-k
		a.ShipIDs[l], a.ShipIDs[r] = a.ShipIDs[r], a.ShipIDs[l]
		a.OriStations[l], a.OriStations[r] = a.OriStations[r], a.OriStations[l]
		a.DesStations[l], a.DesStations[r] = a.DesStations[r], a.DesStations[l]
	}

